A simple rigid body particle integration and sphere-to-sphere overlap resolver:

```cpp
#include <cmath>

struct FVector3D {
    float X, Y, Z;
    float Distance(const FVector3D& Other) const {
        return std::sqrt((X-Other.X)*(X-Other.X) + (Y-Other.Y)*(Y-Other.Y) + (Z-Other.Z)*(Z-Other.Z));
    }
};

struct FRigidParticle {
    FVector3D Position;
    FVector3D Velocity;
    FVector3D Acceleration;
    float Radius = 10.0f;

    // Euler Integration
    void Integrate(float DeltaTime) {
        Velocity.X += Acceleration.X * DeltaTime;
        Velocity.Y += Acceleration.Y * DeltaTime;
        Velocity.Z += Acceleration.Z * DeltaTime;

        Position.X += Velocity.X * DeltaTime;
        Position.Y += Velocity.Y * DeltaTime;
        Position.Z += Velocity.Z * DeltaTime;
    }
};

bool ResolveCollision(FRigidParticle& A, FRigidParticle& B) {
    float Dist = A.Position.Distance(B.Position);
    float SumRadii = A.Radius + B.Radius;

    // Check if overlap exists
    if (Dist < SumRadii) {
        // Overlap detected! Simple push back resolver logic...
        return true;
    }
    return false;
}
```
